import React, { useEffect, useState } from "react";
import "../styles/";

const HeroSection = () => {
    const [time, setTime] = useState(new Date());

    useEffect(() => {
        const interval = setInterval(() => setTime(new Date()), 1000);
        return () => clearInterval(interval);
    }, []);

    const hours = time.getHours() % 12;
    const minutes = time.getMinutes();
    const seconds = time.getSeconds();

    const hourDeg = (hours + minutes / 60) * 30;
    const minuteDeg = (minutes + seconds / 60) * 6;
    const secondDeg = seconds * 6;

    return (
        <section className="hero-section">
            <div className="hero-content">
                <h1>Your business deserves <br /> modern software</h1>
                <p>Glide helps businesses create custom tools for a faster, more efficient way to work—no coding required.</p>
                <div className="hero-buttons">
                    <button className="primary-btn">Build for me</button>
                    <button className="secondary-btn">Start building</button>
                </div>
            </div>

            <div className="hero-image-container">
                <img
                    src="https://oneoceanhub.org/wp-content/uploads/2023/01/SDG-wheel.png"
                    alt="SDG Wheel"
                    className="sdg-image"
                />
                <div className="clock">
                    <div className="hand hour" style={{ transform: `rotate(${hourDeg}deg)` }}></div>
                    <div className="hand minute" style={{ transform: `rotate(${minuteDeg}deg)` }}></div>
                    <div className="hand second" style={{ transform: `rotate(${secondDeg}deg)` }}></div>
                    <div className="center-circle"></div>
                </div>
            </div>
        </section>
    );
};

export default Home;
